python - <<'PY'
import pandas as pd, ast, re
f='/work/ferc_search_20260613_190931.csv'
df=pd.read_csv(f)
print('rows',len(df))
counts={}
rec_details={}
for i,row in df.iterrows():
    aff=ast.literal_eval(row['affiliations']) if isinstance(row['affiliations'],str) else []
    authors=[]
    for a in aff:
        if a.startswith('AUTHOR:'):
            name=a.split(':',1)[1].strip()
            authors.append(name)
    for name in sorted(set(authors)):
        counts[name]=counts.get(name,0)+1
        rec_details.setdefault(name,[]).append(row['title'])
for name,c in sorted(counts.items(), key=lambda x:(-x[1], x[0]))[:20]:
    print(c, name)
    #for t in rec_details[name]: print('  ', t[:80])
print('--- raw affiliation counts all roles')
counts_all={}
for _,row in df.iterrows():
    aff=ast.literal_eval(row['affiliations']) if isinstance(row['affiliations'],str) else []
    for a in set(aff):
        role,name=a.split(':',1)
        if role=='RECIPIENT': continue
        key=(role.strip(),name.strip())
        counts_all[key]=counts_all.get(key,0)+1
for (role,name),c in sorted(counts_all.items(), key=lambda x:(-x[1], x[0][0], x[0][1]))[:30]:
    print(c, role, name)
PY

